components.css:
.ds-card { background: #0f0f1acc; border-radius: 8px; padding: 30px; margin-bottom: 40px; box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2); color: #f4f1e8; font-family: 'Atkinson Hyperlegible Next', sans-serif; line-height: 1.6; overflow: hidden; max-width: 640px; }
.ds-card-h2 { font-family: 'Philosopher', serif; font-size: 2rem; font-weight: 400; color: #b5a693; border-bottom: 1px solid rgba(181, 166, 147, 0.3); padding-bottom: 10px; margin: 0 0 20px 0; }
.ds-arcane-timestamp { font-family: 'Philosopher', serif; font-style: italic; font-size: 1.1rem; color: #b5a693; margin-bottom: 20px; }
.ds-timestamp-icon { color: #b85c69; margin-right: 6px; }
.ds-card-body { margin: 0; }
.ds-drop-cap::first-letter { font-family: 'Philosopher', serif; font-size: 4em; line-height: 0.8; float: left; margin-right: 0.12em; color: #7ba05b; }
.ds-link { color: #7ba05b; text-decoration: none; border-bottom: 1px dotted #7ba05b; transition: border-color 0.2s ease, text-shadow 0.2s ease; }
.ds-link:hover, .ds-link:focus-visible { border-bottom: 1px solid #7ba05b; text-shadow: 0 0 10px rgba(123, 160, 91, 0.5); outline: none; }

.ds-side-content { background: #0f0f1acc; border-radius: 8px; padding: 20px; margin-bottom: 30px; color: #f4f1e8; font-family: 'Atkinson Hyperlegible Next', sans-serif; line-height: 1.6; max-width: 280px; }
.ds-side-title { font-family: 'Philosopher', serif; font-size: 1.2rem; color: #7ba05b; border-bottom: 1px dotted rgba(123, 160, 91, 0.3); padding-bottom: 5px; margin-bottom: 15px; }
.ds-side-list { list-style: none; margin: 0; padding: 0; }
.ds-side-list li { padding: 4px 0; }
.ds-side-list .ds-link { color: #7ba05b; text-decoration: none; border-bottom: 1px dotted #7ba05b; transition: border-color 0.2s ease, text-shadow 0.2s ease; }
.ds-side-list .ds-link:hover, .ds-side-list .ds-link:focus-visible { border-bottom: 1px solid #7ba05b; text-shadow: 0 0 10px rgba(123, 160, 91, 0.5); outline: none; }

.ds-tag { display: inline-flex; align-items: center; gap: 4px; padding: 3px 10px; border-radius: 20px; font-family: 'Atkinson Hyperlegible Next', sans-serif; font-size: 0.8rem; background: rgba(181, 166, 147, 0.2); color: #b5a693; border: 1px solid transparent; text-decoration: none; transition: border-color 0.2s ease, box-shadow 0.2s ease; }
.ds-tag:hover, .ds-tag:focus-visible { border-color: #b5a693; box-shadow: 0 3px 8px rgba(181, 166, 147, 0.2); outline: none; }
.ds-tag-icon { flex: none; }

.ds-arcane-timestamp-standalone { font-family: 'Philosopher', serif; font-style: italic; font-size: 1.1rem; color: #b5a693; }
.ds-cal-icon { color: #b85c69; vertical-align: -3px; margin-right: 6px; }
.ds-link { color: #7ba05b; text-decoration: none; border-bottom: 1px dotted #7ba05b; transition: border-color 0.2s ease, text-shadow 0.2s ease; }
.ds-link:hover, .ds-link:focus-visible { border-bottom: 1px solid #7ba05b; text-shadow: 0 0 10px rgba(123, 160, 91, 0.5); outline: none; }

.ds-illuminated-card { background: #0f0f1acc; border-radius: 8px; padding: 30px; box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2); color: #f4f1e8; font-family: 'Atkinson Hyperlegible Next', sans-serif; line-height: 1.6; max-width: 540px; overflow: hidden; }
.ds-illuminated-h2 { font-family: 'Philosopher', serif; font-size: 2rem; font-weight: 400; color: #b5a693; border-bottom: 1px solid rgba(181, 166, 147, 0.3); padding-bottom: 10px; margin: 0 0 20px 0; }
.ds-illuminated-body { margin: 0 0 16px 0; }
.ds-illuminated-card:has(> .ds-illuminated-h2) .ds-illuminated-body::first-letter { font-family: 'Philosopher', serif; font-size: 4em; line-height: 0.8; float: left; margin-right: 0.12em; color: #7ba05b; }
.ds-illuminated-body-cont { margin: 0; }

.ds-web-button { display: inline-flex; width: 88px; height: 31px; align-items: stretch; border: 1px solid #1a1a2e; box-shadow: inset 1px 1px 0 rgba(244, 241, 232, 0.12), inset -1px -1px 0 rgba(0, 0, 0, 0.4); font-family: 'Verdana', 'Geneva', sans-serif; font-size: 8px; line-height: 1; text-decoration: none; transition: box-shadow 0.2s ease; }
.ds-web-button:hover, .ds-web-button:focus-visible { box-shadow: inset 1px 1px 0 rgba(244, 241, 232, 0.12), inset -1px -1px 0 rgba(0, 0, 0, 0.4), 0 3px 8px rgba(123, 160, 91, 0.2); outline: none; }
.ds-web-button-l { background: #1a1a2e; color: #b5a693; padding: 0 4px; display: flex; align-items: center; font-style: italic; }
.ds-web-button-r { background: #7ba05b; color: #1a1a2e; padding: 0 4px; flex: 1; display: flex; align-items: center; justify-content: center; font-weight: 700; letter-spacing: 0.05em; }

.ds-book-cover-container { display: inline-block; padding: 10px; transition: transform 0.2s ease, box-shadow 0.2s ease; }
.ds-book-cover-container:hover { transform: translateY(-4px); box-shadow: 0 3px 8px rgba(123, 160, 91, 0.3); }
.ds-book-cover { width: 128px; height: 200px; border-radius: 4px; box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2); display: flex; align-items: center; justify-content: center; }
.ds-book-cover-placeholder { background: rgba(181, 166, 147, 0.1); border: 1px solid rgba(181, 166, 147, 0.3); }
.ds-book-cover-placeholder::after { content: '📚'; font-size: 48px; opacity: 0.3; }
@media (prefers-reduced-motion: reduce) { .ds-book-cover-container { transition: none; } .ds-book-cover-container:hover { transform: none; } }

.ds-pagination-card { display: grid; grid-template-columns: 1fr 1fr 1fr; align-items: center; background: #0f0f1acc; border-radius: 8px; padding: 30px; box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2); color: #f4f1e8; font-family: 'Atkinson Hyperlegible Next', sans-serif; max-width: 640px; }
.ds-pagination-prev { text-align: left; }
.ds-pagination-next { text-align: right; }
.ds-pagination-counter { text-align: center; font-family: 'Philosopher', serif; }
.ds-pagination-page { color: #b85c69; font-size: 20px; }
.ds-pagination-icon { color: #7ba05b; }
.ds-link { color: #7ba05b; text-decoration: none; border-bottom: 1px dotted #7ba05b; transition: border-color 0.2s ease, text-shadow 0.2s ease; }
.ds-link:hover, .ds-link:focus-visible { border-bottom: 1px solid #7ba05b; text-shadow: 0 0 10px rgba(123, 160, 91, 0.5); outline: none; }
